export class FilterHtmlIds {
    static { this.FILTER_BASE_NAME = 'filter'; }
    // Dropdown
    static { this.DROPDOWN = (criterionKey) => `${FilterHtmlIds.DROPDOWN_PREFIX}-${criterionKey}`; }
    static { this.DROPDOWN_PREFIX = `${FilterHtmlIds.FILTER_BASE_NAME}-dropdown`; }
    static { this.DROPDOWN_INPUT_GRP = `${FilterHtmlIds.FILTER_BASE_NAME}-inputGroup-sizing-sm`; }
    // Open filter button
    static { this.OPEN_FILTER_BTN = (criterionKey) => `${FilterHtmlIds.OPEN_FILTER_BTN_PREFIX}-${criterionKey}`; }
    static { this.OPEN_FILTER_BTN_PREFIX = `open-filter-btn`; }
    // Checkbox
    static { this.CHECKBOX = (criterionKey, index) => `${FilterHtmlIds.CHECKBOX_PREFIX}-${criterionKey}-${index}`; }
    static { this.CHECKBOX_PREFIX = 'checkbox'; }
    // Apply filter button
    static { this.APPLY_FILTER_BTN = (criterionKey) => `${FilterHtmlIds.APPLY_FILTER_BTN_PREFIX}-${criterionKey}`; }
    static { this.APPLY_FILTER_BTN_PREFIX = `${FilterHtmlIds.FILTER_BASE_NAME}-apply-btn`; }
    // Dropdown item
    static { this.DROPDOWN_ITEM = (criterionKey, optionKey) => `${FilterHtmlIds.DROPDOWN_ITEM_PREFIX}-${criterionKey}-${optionKey}`; }
    static { this.DROPDOWN_ITEM_PREFIX = `${FilterHtmlIds.FILTER_BASE_NAME}-dropdown-item`; }
    // Label
    static { this.LABEL = (criterionKey, optionKey) => `${FilterHtmlIds.LABEL_PREFIX}-${criterionKey}-${optionKey}`; }
    static { this.LABEL_PREFIX = `${FilterHtmlIds.FILTER_BASE_NAME}-label`; }
    // Data attributes
    static { this.DATA_OPTION_KEY = 'data-option-key'; }
    static { this.DATA_CHECKBOX_VALUE = 'data-checkbox-value'; }
}
